import{_ as t,o,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"22. Fixed Term Employment","description":"","frontmatter":{"title":"22. Fixed Term Employment","eba":"Allied Health Professionals 2021-2026","topics":["employment"]},"headers":[],"relativePath":"ebas/allied-health/employment/22-fixed-term-employment.md","filePath":"ebas/allied-health/employment/22-fixed-term-employment.md"}'),i={name:"ebas/allied-health/employment/22-fixed-term-employment.md"};function a(s,e,p,l,m,h){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_22-fixed-term-employment" tabindex="-1">22. Fixed Term Employment <a class="header-anchor" href="#_22-fixed-term-employment" aria-label="Permalink to &quot;22. Fixed Term Employment&quot;">​</a></h1><p><strong>22.1</strong> An Employee may only be employed on a fixed term basis where it is genuine fixed term employment as defined in subclauses 22.2 and 22.3.</p><p><strong>22.2</strong> Genuine fixed term employment is:</p><p><strong>(a)</strong> where the role is for a specific period or purpose and for one of the reasons set out at subclause 22.3; and</p><p><strong>(b)</strong> is not where recurrent funding for the role may end or for a reason other than one specified at subclause 22.3 below.</p><p><strong>22.3</strong> Genuine fixed term employment can only be offered for the following purposes:</p><p><strong>(a)</strong> research projects which, for the purpose of this clause 22 means:</p><p><strong>(i)</strong> there is a definable work activity which has a starting time and which is expected to be completed within an anticipated timeframe;</p><p><strong>(ii)</strong> the funding for the research project does not come from recurrent funding; and</p><p><strong>(iii)</strong> there is no pattern of additional funding being provided or made available to extend the research project;</p><p><strong>(b)</strong> special projects. Indicative examples of special projects are:</p><p><strong>(i)</strong> Specific, Timely Assessment and Triage project (the STAT project), a National Health and Medical Research Council (NHMRC) funded project looking at reducing waiting times;</p><p><strong>(ii)</strong> Language and Literacy project;</p><p><strong>(iii)</strong> Organisational Compliance projects such as those arising from findings of the Royal Commission into Family Violence where Employers must comply with several recommendations within a time specified time frame;</p><p><strong>(c)</strong> backfilling an on-going Employee who has been temporarily seconded to another role;</p><p><strong>(d)</strong> graduate year positions;</p><p><strong>(e)</strong> replacing other Employees who are absent:</p><p><strong>(i)</strong> on leave (including parental, long service or sick leave);</p><p><strong>(ii)</strong> on WorkCover; or</p><p><strong>(iii)</strong> by a flexible work arrangement;</p><p><strong>(f)</strong> any other genuine fixed term arrangement agreed to by the Union at its discretion.</p><p><strong>22.4</strong> Nothing in this clause 22 requires an Employer to use fixed term employment for the purposes listed in subclause 22.3.</p><p><strong>22.5</strong> Appointment</p><p>In the letter of offer, the Employer will advise the Employee in writing of the reason the role is genuine fixed term employment, the duration of the fixed term and the rights of an incumbent Employee (if relevant).</p><p><strong>22.6</strong> Duration of a fixed term contract A contract for genuine fixed term employment cannot be for a period greater than two (2) years unless;</p><p><strong>(a)</strong> otherwise agreed to by the Union at its discretion; or</p><p><strong>(b)</strong> in the case of Peter MacCallum Cancer Institute, the genuine fixed term employment is for a research project as described at subclause 22.3(a), the funding for the project comes from the NHMRC and is for a period of at least 3 years, in which case the contract cannot be for a period greater than three (3) years.</p><p><strong>22.7</strong> Further contract where role continues Where the role that is subject to the genuine fixed term employment will continue beyond the end of the contract, the Employer may offer to extend the fixed term employment for that role by a further contract where it:</p><p><strong>(a)</strong> is still genuine fixed term employment as described at subclause 22.2 and is appropriate in all the circumstances;</p><p><strong>(b)</strong> is still for a purpose listed at subclause 22.3; and</p><p><strong>(c)</strong> does not exceed two (2) years (or three (3) years in accordance with subclause 22.6(b)) or, when any preceding contract is also taken into account, does not result in the appointment exceeding 5 years in total as described at subclause 22.11(a)(ii).</p><p>Example 1 An Employee is engaged on a fixed term basis of 12 months as a parental leave replacement. Just prior to the end of the 12 month period, the incumbent Employee resigns. That is, the Employee on a fixed term contract is no longer replacing another Employee. Under these circumstances, the Employee engaged on a fixed term basis will not have the fixed term extended for a further period other than on a short term basis to allow the Employer to recruit to the role.</p><p>Example 2 An Employee is engaged on a fixed term basis of 2 years as a parental leave replacement. The incumbent applies for a further period of parental leave for another child. Under these circumstances, the Employer may offer to extend the fixed term appointment by a further contract.</p><p><strong>22.8</strong> Where an Employer proposes to offer an additional contract to extend employment in a role in accordance with subclause 22.7 which, if accepted, would result in an Employee being engaged in that role on a fixed term basis for more than two (2) years (or three (3) years in accordance with subclause 22.6(b))</p><p>in total, the Employer will, not less than one (1) month prior to the scheduled expiration of the fixed term contract, write to the Employee stating:</p><p><strong>(a)</strong> that the role will continue beyond the fixed term and the Employer proposes to extend the fixed term appointment by offering a further contract;</p><p><strong>(b)</strong> the period of the proposed further contract;</p><p><strong>(c)</strong> why the Employer considers the further fixed term appointment is genuine fixed term employment (within the meaning of this clause 22) and is appropriate in all the circumstances;</p><p><strong>(d)</strong> that:</p><p><strong>(i)</strong> the Employee is entitled to discuss the offer of a further contract with their representative which may be the Union; and</p><p><strong>(ii)</strong> the Union covered by this Agreement will be notified of the proposed extension of the fixed term appointment but that personal information will not be disclosed; and</p><p><strong>(e)</strong> that if the Employee or their representative (including the Union) disputes that the proposed contract is for genuine fixed term employment, either is entitled to notify a dispute under <a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a> (Dispute Resolution Procedure) of this Agreement.</p><p><strong>22.9</strong> Where an Employer proposes to offer an additional contract to extend employment in a role in accordance with subclause 22.7 which, if accepted, would result in an Employee being engaged in that role on a fixed term basis for more than 2 years (or three (3) years in accordance with subclause 22.6(b)) in total, not less than one (1) month prior to the scheduled expiration of the fixed term, the Employer will write to the Union stating:</p><p><strong>(a)</strong> the information described at subclause 22.8(a), (b) and (c); and</p><p><strong>(b)</strong> the classification, grade and Department/area of the genuine fixed term employment and the length of the fixed term appointment in total; but will not disclose the personal information of the Employee without the Employee’s consent.</p><p><strong>22.10</strong> Where the Employer proposes a further contract to extend a fixed term employment in accordance with subclause 22.7 the Employer will, where requested by the Employee or the Union, meet to discuss the proposed extension of the fixed term employment by a further contract and provide the Employee and/or the Union with any relevant information relating to why the proposed extended fixed term employment is genuine fixed term employment.</p><p><strong>22.11</strong> Conversion to permanent employment</p><p><strong>(a)</strong> If:</p><p><strong>(i)</strong> the period of fixed term contract exceeds two (2) years (or three (3) years in accordance with subclause 22.6(b)) unless otherwise agreed to by the Union in accordance with subclause 22.6;</p><p><strong>(ii)</strong> an Employee’s total period of fixed term employment (where there has been more than one fixed term contract) exceeds five (5) years;</p><p><strong>(iii)</strong> the Employee engaged pursuant to this clause 22 is re-engaged within thirteen weeks (including the total period of accrued annual leave paid on termination);</p><p><strong>(iv)</strong> in engaging a fixed term Employee or extending the fixed term engagement the Employer does not comply with this clause 22 or, in the case of the timeframes at subclauses 22.8 and 22.9, does not substantially comply with those timeframes; or</p><p><strong>(v)</strong> the Employer has employed the Employee on more than five (5) fixed term contracts; the Employee will be deemed to have been originally employed under <a href="/eba/ebas/allied-health/employment/18-full-time-employment.html">clause 18</a> - Full-time employment, or <a href="/eba/ebas/allied-health/employment/19-part-time-employment.html">clause 19</a> - Part-time employment.</p><p><strong>(b)</strong> For the purpose of this subclause 22.11, does not substantially comply means that the Employer’s failure to adhere to the prescribed timeframes is such that either or both the Employee and the Union cannot:</p><p><strong>(i)</strong> give proper consideration to;</p><p><strong>(ii)</strong> consult with the other on; and</p><p><strong>(iii)</strong> seek advice on; the proposed extension of fixed term employment and be satisfied that the fixed term employment offered is genuine fixed term employment within the meaning of this Agreement.</p><p><strong>22.12</strong> Separate fixed term positions The provisions of subclauses 22.8 and 22.9 do not apply where an Employee applies for separate fixed term positions.</p><p><strong>22.13</strong> Anti-avoidance Separate fixed term positions means positions that are genuine fixed term employment within the meaning of subclause 22.3 and which are genuinely separate and distinct, and does not include a single position that has been amended from one contract to the next.</p><p><strong>22.14</strong> Consideration of Fixed Term employment The Employer will consider whether it could utilise a permanent reliever rather than a fixed term Employee for long term leave relief.</p><p><strong>22.15</strong> Graduates Employees will be provided with ongoing employment following completion of their graduate year positions, where it is appropriate in all the circumstances and a suitable vacancy exists.</p><p><strong>22.16</strong> Entitlements for fixed term employment Employees engaged on a fixed term basis pursuant to this clause 22 will receive the pay, entitlements and other conditions a full-time Employee receives where their work accords with <a href="/eba/ebas/allied-health/employment/18-full-time-employment.html">clause 18</a> (Full-Time Employment), otherwise they will</p><p>receive the pay, entitlements and other conditions provided for a part-time Employee under <a href="/eba/ebas/allied-health/employment/19-part-time-employment.html">clause 19</a>.</p>',63)])])}const g=t(i,[["render",a]]);export{c as __pageData,g as default};
